/**
 * Toggle a disclosure panel with aria-expanded state.
 */
export class DisclosureWidget {
  /** @type {HTMLButtonElement} */
  #button;

  /** @type {HTMLElement} */
  #panel;

  /**
   * @param {HTMLButtonElement} button
   * @param {HTMLElement} panel
   */
  constructor(button, panel) {
    this.#button = button;
    this.#panel = panel;
    this.#button.setAttribute('aria-expanded', 'false');
    this.#panel.hidden = true;
  }

  /** Toggle panel visibility. */
  toggle() {
    const expanded = this.#button.getAttribute('aria-expanded') === 'true';
    const next = !expanded;
    this.#button.setAttribute('aria-expanded', String(next));
    this.#panel.hidden = !next;
  }

  /** Attach click listener on the button. */
  bind() {
    this.#button.addEventListener('click', () => this.toggle());
  }
}
